#include <stdio.h>
#include <limits.h>
int main() {
    int N, X, Y;
    scanf("%d %d %d", &N, &X, &Y);
    int contests[N][2];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &contests[i][0], &contests[i][1]);
    }
    int V[X], W[Y];
    for (int i = 0; i < X; i++) {
        scanf("%d", &V[i]);
    }
    for (int i = 0; i < Y; i++) {
        scanf("%d", &W[i]);
    }
    int minTime = INT_MAX;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < X; j++) {
            for (int k = 0; k < Y; k++) {
                if (V[j] <= contests[i][0] && contests[i][1] <= W[k]) {
                    int time = W[k] - V[j] + 1;
                    minTime = (time < minTime) ? time : minTime;
                }
            }
        }
    }
    printf("%d\n", minTime);
    return 0;
}

