import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int X = sc.nextInt();
        int Y = sc.nextInt();
        int[][] contests = new int[N][2];
        for (int i = 0; i < N; i++) {
            contests[i][0] = sc.nextInt();
            contests[i][1] = sc.nextInt();
        }
        int[] V = new int[X];
        for (int i = 0; i < X; i++) {
            V[i] = sc.nextInt();
        }
        int[] W = new int[Y];
        for (int i = 0; i < Y; i++) {
            W[i] = sc.nextInt();
        }
        int minTime = Integer.MAX_VALUE;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < X; j++) {
                for (int k = 0; k < Y; k++) {
                    if (V[j] <= contests[i][0] && contests[i][1] <= W[k]) {
                        int time = W[k] - V[j] + 1;
                        minTime = Math.min(time, minTime);
                    }
                }
            }
        }
        System.out.println(minTime);
    }
}

